import{_ as e,c as s,o as i,aj as t}from"./chunks/framework.VtnL2jmu.js";const b=JSON.parse('{"title":"bat：插了翅膀的 cat","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/bat插了翅膀的cat.md","filePath":"Linux/bat插了翅膀的cat.md"}'),n={name:"Linux/bat插了翅膀的cat.md"};function l(r,a,c,o,d,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="bat-插了翅膀的-cat" tabindex="-1">bat：插了翅膀的 cat <a class="header-anchor" href="#bat-插了翅膀的-cat" aria-label="Permalink to “bat：插了翅膀的 cat”">​</a></h1><p><strong>bat</strong> 的定位是 <em>A cat clone with wings</em>（插了翅膀的 cat 复刻版）。</p><hr><h3 id="_1-为什么它是全栈开发者的心头好" tabindex="-1">1. 为什么它是全栈开发者的心头好？ <a class="header-anchor" href="#_1-为什么它是全栈开发者的心头好" aria-label="Permalink to “1. 为什么它是全栈开发者的心头好？”">​</a></h3><ul><li><strong>语法高亮</strong>：它内置了对 Java, SQL, JSON, YAML, Python 等数百种语言的自动高亮。</li><li><strong>Git 集成</strong>：如果你的项目在 Git 管理下，<code>bat</code> 会在侧边栏显示 <code>+</code>, <code>-</code>, <code>~</code> 来告诉你哪些行是新加的、删除的或修改过的。</li><li><strong>自动分页</strong>：如果文件太长，它会自动调用 <code>less</code> 进行分页，不用担心大文件瞬间淹没你的终端。</li><li><strong>显示不可见字符</strong>：可以显示空格、制表符等（对排查 YAML 缩进错误极其有用）。</li></ul><hr><h3 id="_2-安装-避坑说明" tabindex="-1">2. 安装（避坑说明） <a class="header-anchor" href="#_2-安装-避坑说明" aria-label="Permalink to “2. 安装（避坑说明）”">​</a></h3><p>在 Ubuntu/Debian 系统中，有一个小细节：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sudo apt update</span></span>
<span class="line"><span>sudo apt install bat</span></span></code></pre></div><p><strong>⚠️ 注意：</strong> 在 Ubuntu 上，由于软件包命名冲突，安装后的命令名可能是 <code>batcat</code> 而不是 <code>bat</code>。为了用起来顺手，建议在 <code>.rc</code> 里设置一个别名：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 在 ~/.rc 末尾添加</span></span>
<span class="line"><span>alias bat=&#39;batcat&#39;</span></span>
<span class="line"><span>source ~/.rc</span></span></code></pre></div><hr><h3 id="_3-实战使用技巧" tabindex="-1">3. 实战使用技巧 <a class="header-anchor" href="#_3-实战使用技巧" aria-label="Permalink to “3. 实战使用技巧”">​</a></h3><h4 id="_1-基础查看-带高亮、带行号" tabindex="-1">① 基础查看（带高亮、带行号） <a class="header-anchor" href="#_1-基础查看-带高亮、带行号" aria-label="Permalink to “① 基础查看（带高亮、带行号）”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>bat src/main/resources/application.yml</span></span></code></pre></div><p>你会发现，原本灰蒙蒙的配置文件的缩进和键值对变得非常清晰。</p><h4 id="_2-配合-httpie-调试接口" tabindex="-1">② 配合 HTTPie 调试接口 <a class="header-anchor" href="#_2-配合-httpie-调试接口" aria-label="Permalink to “② 配合 HTTPie 调试接口”">​</a></h4><p>如果你想把接口返回的 JSON 存成文件再看，或者直接管道输出：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http :8888/api/users | bat -l json</span></span></code></pre></div><p><em><code>-l json</code> 强制指定以 JSON 格式渲染高亮。</em></p><h4 id="_3-配合-fzf-实现-真·神级预览" tabindex="-1">③ 配合 fzf 实现“真·神级预览” <a class="header-anchor" href="#_3-配合-fzf-实现-真·神级预览" aria-label="Permalink to “③ 配合 fzf 实现“真·神级预览””">​</a></h4><p>这是最强联动方案。修改你的预览配置：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fzf --preview &#39;bat --style=numbers --color=always --line-range :500 {}&#39;</span></span></code></pre></div><p>这样你在 <code>fzf</code> 搜文件时，右侧会通过 <code>bat</code> 显示带行号、带高亮的文件内容，体验完全不输 IDEA 的文件搜索。</p>`,24)])])}const g=e(n,[["render",l]]);export{b as __pageData,g as default};
